import React, { useState, useEffect } from 'react';
import {
  Calendar,
  Bot,
  MessageSquare,
  Activity,
  Shield,
  Clock,
  Building2,
  ChevronRight,
  Sparkles,
} from 'lucide-react';

const FEATURES = [
  { 
    icon: Calendar, 
    label: 'Smart Appointment Booking', 
    desc: 'Book visits instantly with real-time doctor availability' 
  },
  { 
    icon: Bot, 
    label: 'AI-Powered Diagnosis', 
    desc: 'Get instant health insights powered by advanced AI' 
  },
  { 
    icon: MessageSquare, 
    label: 'Direct Doctor Messaging', 
    desc: '24/7 consultation access with your healthcare providers' 
  },
  { 
    icon: Activity, 
    label: 'Health Tracking & Records', 
    desc: 'Complete medical history and health metrics tracking' 
  },
  { 
    icon: Shield, 
    label: 'Secure & Private', 
    desc: 'HIPAA compliant platform with end-to-end encryption' 
  },
  { 
    icon: Clock, 
    label: '24/7 Access', 
    desc: 'Available anytime, anywhere on any device' 
  },
];

const STATS = [
  { number: '50K+', label: 'Active Users' },
  { number: '98%', label: 'Satisfaction' },
  { number: '24/7', label: 'Support' },
];

// Generate random particles
const generateParticles = () => {
  return Array.from({ length: 30 }, (_, i) => ({
    id: i,
    left: Math.random() * 100,
    top: Math.random() * 100,
    size: Math.random() * 3 + 1,
    duration: Math.random() * 20 + 10,
    delay: Math.random() * 5,
  }));
};

export default function LandingPage({ onSignIn, onSignUp }) {
  const [mousePos, setMousePos] = useState({ x: 0, y: 0 });
  const [particles] = useState(generateParticles());

  useEffect(() => {
    const handleMouseMove = (e) => {
      setMousePos({ x: e.clientX, y: e.clientY });
    };
    window.addEventListener('mousemove', handleMouseMove);
    return () => window.removeEventListener('mousemove', handleMouseMove);
  }, []);

  return (
    <div style={{ 
      minHeight: '100vh', 
      background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
      position: 'relative', 
      overflow: 'hidden',
      color: 'white',
    }}>
      <style>{`
        @keyframes fadeInUp {
          from { opacity: 0; transform: translateY(40px); }
          to { opacity: 1; transform: translateY(0); }
        }

        @keyframes fadeInDown {
          from { opacity: 0; transform: translateY(-40px); }
          to { opacity: 1; transform: translateY(0); }
        }

        @keyframes slideInLeft {
          from { opacity: 0; transform: translateX(-60px); }
          to { opacity: 1; transform: translateX(0); }
        }

        @keyframes slideInRight {
          from { opacity: 0; transform: translateX(60px); }
          to { opacity: 1; transform: translateX(0); }
        }

        @keyframes float {
          0%, 100% { transform: translateY(0px); }
          50% { transform: translateY(-20px); }
        }

        @keyframes gentleFloat {
          0%, 100% { transform: translateY(0px) rotate(0deg); }
          50% { transform: translateY(-15px) rotate(2deg); }
        }

        @keyframes pulse {
          0%, 100% { transform: scale(1); opacity: 1; }
          50% { transform: scale(1.1); opacity: 0.8; }
        }

        @keyframes spin360 {
          from { transform: rotate(0deg); }
          to { transform: rotate(360deg); }
        }

        @keyframes shimmer {
          0% { background-position: -1000px 0; }
          100% { background-position: 1000px 0; }
        }

        @keyframes scaleIn {
          from { opacity: 0; transform: scale(0.9); }
          to { opacity: 1; transform: scale(1); }
        }

        @keyframes driftParticle {
          0% { opacity: 0.3; transform: translateY(100vh) translateX(0px); }
          50% { opacity: 0.6; }
          100% { opacity: 0.3; transform: translateY(-100vh) translateX(100px); }
        }
      `}</style>

      {/* Floating Particles Background */}
      <div style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: '100%', overflow: 'hidden', zIndex: 0 }}>
        {particles.map(particle => (
          <div
            key={particle.id}
            style={{
              position: 'absolute',
              left: `${particle.left}%`,
              top: `${particle.top}%`,
              width: `${particle.size}px`,
              height: `${particle.size}px`,
              background: 'rgba(255, 255, 255, 0.5)',
              borderRadius: '50%',
              animation: `driftParticle ${particle.duration}s linear ${particle.delay}s infinite`,
              boxShadow: `0 0 ${particle.size * 2}px rgba(255, 255, 255, 0.8)`,
            }}
          />
        ))}
      </div>

      {/* Mouse Follower Gradient */}
      <div
        style={{
          position: 'fixed',
          width: 300,
          height: 300,
          borderRadius: '50%',
          background: `radial-gradient(circle, rgba(255,255,255,0.1) 0%, transparent 70%)`,
          pointerEvents: 'none',
          zIndex: 1,
          left: mousePos.x - 150,
          top: mousePos.y - 150,
          transition: 'all 0.1s ease-out',
        }}
      />

      {/* Content Container */}
      <div style={{ position: 'relative', zIndex: 2 }}>
        {/* Header */}
        <div style={{
          padding: '24px 48px',
          display: 'flex',
          alignItems: 'center',
          gap: 12,
          animation: 'fadeInDown 0.8s ease-out',
          background: 'rgba(0, 0, 0, 0.1)',
          backdropFilter: 'blur(10px)',
          borderBottom: '1px solid rgba(255, 255, 255, 0.1)',
        }}>
          <div style={{
            background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
            padding: '8px 12px',
            borderRadius: 8,
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
          }}>
            <Building2 size={24} strokeWidth={1.5} />
          </div>
          <div>
            <div style={{ fontSize: 18, fontWeight: 700 }}>Health Easy Portal</div>
            <div style={{ fontSize: 12, opacity: 0.85 }}>Your all-in-one health management platform</div>
          </div>
        </div>

        {/* Hero Section */}
        <div style={{
          padding: '80px 48px 60px',
          textAlign: 'center',
          maxWidth: 900,
          margin: '0 auto',
        }}>
          <div style={{
            fontSize: 56,
            fontWeight: 900,
            marginBottom: 24,
            lineHeight: 1.2,
            animation: 'fadeInUp 0.8s ease-out',
            background: 'linear-gradient(90deg, #ffffff 0%, #e0e7ff 100%)',
            backgroundSize: '200% 200%',
            WebkitBackgroundClip: 'text',
            WebkitTextFillColor: 'transparent',
            backgroundClip: 'text',
            animation: 'fadeInUp 0.8s ease-out, shimmer 3s linear infinite 0.8s',
          }}>
            Transform Your <br /> Healthcare Experience
          </div>
          <p style={{
            fontSize: 18,
            opacity: 0.95,
            marginBottom: 40,
            animation: 'fadeInUp 0.8s ease-out 0.15s both',
            lineHeight: 1.7,
          }}>
            Connect with healthcare professionals, track your health, and get AI-powered insights—all in one secure platform.
          </p>
        </div>

        {/* Features Section - Diagonal Staggered Layout */}
        <div style={{
          padding: '40px 48px',
          maxWidth: 1200,
          margin: '0 auto',
          marginBottom: 60,
        }}>
          <div style={{
            display: 'flex',
            flexDirection: 'column',
            gap: 48,
          }}>
            {FEATURES.map((feature, idx) => {
              const isEven = idx % 2 === 0;
              const AnimIcon = feature.icon;
              
              return (
                <div
                  key={idx}
                  style={{
                    display: 'flex',
                    alignItems: 'center',
                    gap: 48,
                    flexDirection: isEven ? 'row' : 'row-reverse',
                    animation: isEven 
                      ? `slideInLeft 0.8s ease-out ${0.1 * idx}s both`
                      : `slideInRight 0.8s ease-out ${0.1 * idx}s both`,
                  }}
                >
                  {/* Icon */}
                  <div
                    style={{
                      width: 120,
                      height: 120,
                      minWidth: 120,
                      background: 'rgba(255, 255, 255, 0.1)',
                      backdropFilter: 'blur(10px)',
                      borderRadius: 24,
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center',
                      border: '1px solid rgba(255, 255, 255, 0.2)',
                      animation: `spin360 20s linear infinite, pulse 3s ease-in-out 0.5s infinite`,
                      cursor: 'pointer',
                      transition: 'all 0.3s ease',
                      position: 'relative',
                    }}
                    onMouseOver={e => {
                      e.currentTarget.style.background = 'rgba(255, 255, 255, 0.15)';
                      e.currentTarget.style.transform = 'scale(1.1)';
                      e.currentTarget.style.boxShadow = '0 0 40px rgba(102, 126, 234, 0.6)';
                    }}
                    onMouseOut={e => {
                      e.currentTarget.style.background = 'rgba(255, 255, 255, 0.1)';
                      e.currentTarget.style.transform = 'scale(1)';
                      e.currentTarget.style.boxShadow = 'none';
                    }}
                  >
                    <AnimIcon size={56} strokeWidth={1.5} />
                  </div>

                  {/* Content */}
                  <div
                    style={{
                      flex: 1,
                      background: 'rgba(255, 255, 255, 0.05)',
                      backdropFilter: 'blur(10px)',
                      borderRadius: 16,
                      padding: 32,
                      border: '1px solid rgba(255, 255, 255, 0.1)',
                      transition: 'all 0.3s ease',
                      cursor: 'pointer',
                      animation: `fadeInUp 0.8s ease-out ${0.1 * idx + 0.2}s both`,
                    }}
                    onMouseOver={e => {
                      e.currentTarget.style.background = 'rgba(255, 255, 255, 0.1)';
                      e.currentTarget.style.transform = isEven ? 'translateX(-20px)' : 'translateX(20px)';
                      e.currentTarget.style.boxShadow = '0 10px 40px rgba(0, 0, 0, 0.2)';
                    }}
                    onMouseOut={e => {
                      e.currentTarget.style.background = 'rgba(255, 255, 255, 0.05)';
                      e.currentTarget.style.transform = 'translateX(0)';
                      e.currentTarget.style.boxShadow = 'none';
                    }}
                  >
                    <h3 style={{
                      fontSize: 24,
                      fontWeight: 800,
                      marginBottom: 12,
                      display: 'flex',
                      alignItems: 'center',
                      gap: 8,
                    }}>
                      {feature.label}
                      <ChevronRight size={20} style={{ marginLeft: 'auto', transition: 'all 0.3s ease' }} />
                    </h3>
                    <p style={{
                      fontSize: 16,
                      color: 'rgba(255, 255, 255, 0.85)',
                      lineHeight: 1.6,
                    }}>
                      {feature.desc}
                    </p>
                  </div>
                </div>
              );
            })}
          </div>
        </div>

        {/* Stats Section */}
        <div style={{
          padding: '60px 48px',
          textAlign: 'center',
          animation: 'fadeInUp 0.8s ease-out 0.5s both',
        }}>
          <div style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))',
            gap: 24,
            marginBottom: 40,
          }}>
            {STATS.map((stat, idx) => (
              <div
                key={idx}
                style={{
                  background: 'rgba(255, 255, 255, 0.1)',
                  backdropFilter: 'blur(10px)',
                  borderRadius: 16,
                  padding: 32,
                  border: '1px solid rgba(255, 255, 255, 0.2)',
                  animation: `gentleFloat 4s ease-in-out ${idx * 0.5}s infinite, fadeInUp 0.8s ease-out ${0.6 + idx * 0.1}s both`,
                  cursor: 'pointer',
                  transition: 'all 0.3s ease',
                }}
                onMouseOver={e => {
                  e.currentTarget.style.transform = 'translateY(-10px)';
                  e.currentTarget.style.boxShadow = '0 20px 40px rgba(0, 0, 0, 0.3)';
                }}
                onMouseOut={e => {
                  e.currentTarget.style.transform = 'translateY(0)';
                  e.currentTarget.style.boxShadow = 'none';
                }}
              >
                <div style={{ fontSize: 36, fontWeight: 900, marginBottom: 8 }}>
                  {stat.number}
                </div>
                <div style={{ fontSize: 14, opacity: 0.9 }}>
                  {stat.label}
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* CTA Section */}
        <div style={{
          padding: '80px 48px',
          textAlign: 'center',
          animation: 'scaleIn 0.8s ease-out 0.8s both',
        }}>
          <h2 style={{
            fontSize: 36,
            fontWeight: 800,
            marginBottom: 32,
            animation: 'fadeInUp 0.8s ease-out 0.8s both',
          }}>
            Ready to Take Control of Your Health?
          </h2>

          <div style={{
            display: 'flex',
            gap: 20,
            justifyContent: 'center',
            flexWrap: 'wrap',
            animation: 'fadeInUp 0.8s ease-out 0.9s both',
          }}>
            <button
              onClick={onSignIn}
              style={{
                padding: '18px 52px',
                background: 'white',
                color: '#667eea',
                border: 'none',
                borderRadius: 12,
                fontSize: 16,
                fontWeight: 700,
                cursor: 'pointer',
                display: 'flex',
                alignItems: 'center',
                gap: 8,
                transition: 'all 0.3s ease',
                boxShadow: '0 10px 30px rgba(0, 0, 0, 0.3)',
              }}
              onMouseOver={e => {
                e.currentTarget.style.transform = 'translateY(-4px) scale(1.05)';
                e.currentTarget.style.boxShadow = '0 15px 40px rgba(0, 0, 0, 0.4)';
              }}
              onMouseOut={e => {
                e.currentTarget.style.transform = 'translateY(0) scale(1)';
                e.currentTarget.style.boxShadow = '0 10px 30px rgba(0, 0, 0, 0.3)';
              }}
            >
              Sign In Now
              <ChevronRight size={18} strokeWidth={2} />
            </button>

            <button
              onClick={onSignUp}
              style={{
                padding: '18px 52px',
                background: 'rgba(255, 255, 255, 0.15)',
                color: 'white',
                border: '2px solid rgba(255, 255, 255, 0.4)',
                borderRadius: 12,
                fontSize: 16,
                fontWeight: 700,
                cursor: 'pointer',
                display: 'flex',
                alignItems: 'center',
                gap: 8,
                transition: 'all 0.3s ease',
                backdropFilter: 'blur(10px)',
              }}
              onMouseOver={e => {
                e.currentTarget.style.background = 'rgba(255, 255, 255, 0.25)';
                e.currentTarget.style.borderColor = 'rgba(255, 255, 255, 0.6)';
                e.currentTarget.style.transform = 'translateY(-4px) scale(1.05)';
              }}
              onMouseOut={e => {
                e.currentTarget.style.background = 'rgba(255, 255, 255, 0.15)';
                e.currentTarget.style.borderColor = 'rgba(255, 255, 255, 0.4)';
                e.currentTarget.style.transform = 'translateY(0) scale(1)';
              }}
            >
              Create Account
              <ChevronRight size={18} strokeWidth={2} />
            </button>
          </div>
        </div>

        {/* Footer */}
        <div style={{
          padding: '32px 48px',
          textAlign: 'center',
          borderTop: '1px solid rgba(255, 255, 255, 0.1)',
          fontSize: 13,
          opacity: 0.8,
          animation: 'fadeInUp 0.8s ease-out 1s both',
        }}>
          <p style={{ marginBottom: 8 }}>🔒 HIPAA Compliant • End-to-End Encrypted • Available 24/7</p>
          <p style={{ opacity: 0.6 }}>© 2026 Health Easy Portal. All rights reserved.</p>
        </div>
      </div>
    </div>
  );
}
